  margin: 20px;
  display: flex;
  gap: 20px;
  height: 140px;
}

.description-box {
  flex: 1;
  background-color: #f5f5f5;
  border-radius: 4px;
  padding: 15px;
  margin-bottom: 0;
  color: #333;
  overflow-y: auto;
}

.description-box.describing, .description-box.ready {
    background-color: #e9ecef;
    color: #6c757d;
    font-style: italic;
  }

.description-controls {
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  width: 200px;
  gap: 10px;
}

.description-controls button {
    padding: 8px 16px;
    border: none;
    border-radius: 4px;
    background-color: #007bff;
    color: white;
    cursor: pointer;
    white-space: nowrap;
  }

.description-controls button:disabled {
      background-color: #cccccc;
      cursor: not-allowed;
    }

.description-controls button:hover:not(:disabled) {
      background-color: #0056b3;
    }

.description-controls button.reset-button {
        background-color: #007bff;
    }

.description-controls button.reset-button:hover:not(:disabled) {
        background-color: #0056b3;
      }

.description-controls button.reset-button:disabled {
        background-color: #cccccc;
      }

#root {
  display: flex;
  flex-direction: column;
  height: 100vh;
}

.stage-container {
  flex: 1;
